#include <stdio.h>
int max(int a, int b) { return (a > b) ? a : b; }
int knapsack(int n, int max_length, int lengths[], int values[]) {
    int dp[n + 1][max_length + 1];
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= max_length; j++) {
            if (i == 0 || j == 0) {
                dp[i][j] = 0;
            } else if (lengths[i - 1] <= j) {
                dp[i][j] = max(values[i - 1] + dp[i - 1][j - lengths[i - 1]], dp[i - 1][j]);
            } else {
                dp[i][j] = dp[i - 1][j];
            }
        }
    }
    return dp[n][max_length];
}
int main() {
    int n;
    scanf("%d", &n);
    int lengths[n], values[n];
    int max_length = 0;
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &lengths[i], &values[i]);
        max_length += lengths[i];
    }
    printf("%d\n", knapsack(n, max_length, lengths, values));
    return 0;
}

