function knapsack(n, max_length, lengths, values) {
    let dp = new Array(n + 1).fill(0).map(() => new Array(max_length + 1).fill(0));
    for (let i = 0; i <= n; i++) {
        for (let j = 0; j <= max_length; j++) {
            if (i == 0 || j == 0) {
                dp[i][j] = 0;
            } else if (lengths[i - 1] <= j) {
                dp[i][j] = max(values[i - 1] + dp[i - 1][j - lengths[i - 1]], dp[i - 1][j]);
            } else {
                dp[i][j] = dp[i - 1][j];
            }
        }
    }
    return dp[n][max_length];
}

